INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1000001, 1, 62, "2030/01/01 14:59:59", 3.414, 2, 1, -416.5, 190805, 0.0, 1, "2025/01/31 12:00:00", "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", "カリン");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1000002, 1, 62, "2030/01/01 14:59:59", 3.099, 2, 1, -416.5, 190805, 0.0, 2, "2025/01/31 12:00:00", "ミッションをクリアして、\n報酬をゲットしましょう！", "カリン");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1000003, 1, 63, "2030/01/01 14:59:59", 2.801, 2, 1, -416.5, 190805, 0.0, 3, "2025/01/31 12:00:00", "受け取ることができる\n報酬があるようです\n確認してみてください", "カリン");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1000004, 1, 63, "2030/01/01 14:59:59", 0.0, 2, 2, -416.5, 190805, 0.0, 4, "2025/01/31 12:00:00", "報酬がもらえますよ！\nチェックしてみてください", "カリン");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1000005, 1, 64, "2030/01/01 14:59:59", 2.12, 1, 2, -363.0, 190805, 0.0, 5, "2025/01/31 12:00:00", "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", "カリン");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1000006, 1, 64, "2030/01/01 14:59:59", 1.68, 2, 1, -363.0, 190805, 0.0, 6, "2025/01/31 12:00:00", "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", "カリン");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1000007, 1, 64, "2030/01/01 14:59:59", 2.33, 1, 2, -363.0, 190805, 0.0, 7, "2025/01/31 12:00:00", "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", "カリン");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1020101, 10201, 61, "2030/01/01 14:59:59", 5.18, 7, 3, -285.0, 133701, -6.0, 101, "2025/01/31 12:00:00", "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", "ラビリスタ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1020102, 10201, 61, "2030/01/01 14:59:59", 8.77, 2, 1, -285.0, 133901, -2.0, 201, "2025/01/31 12:00:00", "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", "クリスティーナ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1020103, 10201, 61, "2030/01/01 14:59:59", 15.5, 1, 6, -285.0, 133801, 0.0, 301, "2025/01/31 12:00:00", "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", "ネネカ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1020201, 10202, 61, "2030/01/01 14:59:59", 9.061, 5, 2, -285.0, 134301, 0.0, 101, "2025/02/28 12:00:00", "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", "ランファ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1020202, 10202, 61, "2030/01/01 14:59:59", 7.699, 2, 1, -285.0, 134401, 0.0, 201, "2025/02/28 12:00:00", "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", "チカ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1020301, 10203, 61, "2030/01/01 14:59:59", 8.595, 2, 1, -285.0, 134601, 0.0, 101, "2025/03/31 12:00:00", "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", "アオイ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1020302, 10203, 61, "2030/01/01 14:59:59", 7.758, 2, 1, -285.0, 134501, 0.0, 201, "2025/03/31 12:00:00", "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", "クローチェ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1020401, 10204, 61, "2030/01/01 14:59:59", 7.0, 6, 2, -285.0, 132302, 0.0, 101, "2025/04/30 12:00:00", "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", "ルイズマリー");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1020402, 10204, 61, "2030/01/01 14:59:59", 7.904, 2, 1, -285.0, 132402, 0.0, 201, "2025/04/30 12:00:00", "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", "イロハ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1020403, 10204, 61, "2030/01/01 14:59:59", 8.487, 2, 4, -285.0, 132502, 0.0, 301, "2025/04/30 12:00:00", "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", "ソノ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1020502, 10205, 61, "2030/01/01 14:59:59", 8.763, 2, 1, -285.0, 134901, 0.0, 101, "2025/05/31 12:00:00", "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", "カノン");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1020503, 10205, 61, "2030/01/01 14:59:59", 6.417, 3, 1, -285.0, 134801, 0.0, 201, "2025/05/31 12:00:00", "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", "ツムギ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1020601, 10206, 61, "2030/01/01 14:59:59", 10.335, 7, 3, -285.0, 135001, 0.0, 101, "2025/06/30 12:00:00", "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", "エリス");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1020602, 10206, 61, "2030/01/01 14:59:59", 6.281, 4, 2, -285.0, 135101, 0.0, 201, "2025/06/30 12:00:00", "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", "シェフィ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1020603, 10206, 61, "2030/01/01 14:59:59", 12.244, 2, 1, -285.0, 135201, 0.0, 301, "2025/06/30 12:00:00", "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", "プレシア");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1020701, 10207, 61, "2030/01/01 14:59:59", 6.339, 8, 2, -285.0, 135301, 0.0, 101, "2025/07/31 12:00:00", "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", "クリア");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1020702, 10207, 61, "2030/01/01 14:59:59", 8.184, 9, 7, -285.0, 135401, 0.0, 201, "2025/07/31 12:00:00", "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", "アネモネ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1020801, 10208, 61, "2030/01/01 14:59:59", 3.906, 2, 9, -285.0, 129101, 0.0, 101, "2025/08/31 12:00:00", "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", "アイラ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1020802, 10208, 61, "2030/01/01 14:59:59", 14.465, 2, 1, -285.0, 129201, 0.0, 201, "2025/08/31 12:00:00", "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", "シナツ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1020803, 10208, 61, "2030/01/01 14:59:59", 8.662, 3, 4, -285.0, 100101, 0.0, 301, "2025/08/31 12:00:00", "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", "ヒヨリ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1020804, 10208, 61, "2030/01/01 14:59:59", 10.915, 3, 1, -285.0, 100301, 0.0, 401, "2025/08/31 12:00:00", "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", "レイ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1020901, 10209, 61, "2030/01/01 14:59:59", 6.042, 7, 1, -285.0, 135802, 0.0, 101, "2025/09/30 12:00:00", "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", "ユキノ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1020902, 10209, 61, "2030/01/01 14:59:59", 9.402, 1, 4, -285.0, 135903, 0.0, 201, "2025/09/30 12:00:00", "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", "サツキ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1020903, 10209, 61, "2030/01/01 14:59:59", 8.16, 1, 8, -285.0, 136902, 0.0, 301, "2025/09/30 12:00:00", "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", "ルルィ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021001, 10210, 61, "2030/01/01 14:59:59", 5.0, 2, 3, -285.0, 137401, 0.0, 101, "2025/10/31 12:00:00", "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", "カスミ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021002, 10210, 61, "2030/01/01 14:59:59", 8.12, 1, 4, -285.0, 136001, 0.0, 201, "2025/10/31 12:00:00", "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", "アラクネ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021003, 10210, 61, "2030/01/01 14:59:59", 6.386, 2, 4, -285.0, 136202, 0.0, 301, "2025/10/31 12:00:00", "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", "ナーナ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021101, 10211, 61, "2030/01/01 14:59:59", 7.438, 4, 3, -285.0, 136402, 0.0, 101, "2025/11/30 12:00:00", "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", "ユイ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021102, 10211, 61, "2030/01/01 14:59:59", 8.35, 5, 1, -285.0, 136302, 0.0, 201, "2025/11/30 12:00:00", "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", "ミソラ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021201, 10212, 61, "2030/01/01 14:59:59", 5.0, 2, 1, -285.0, 136501, 0.0, 101, "2025/12/31 12:00:00", "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", "シズル");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021202, 10212, 61, "2030/01/01 14:59:59", 5.25, 2, 1, -285.0, 137902, 0.0, 201, "2025/12/31 12:00:00", "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", "リノ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021203, 10212, 61, "2030/01/01 14:59:59", 7.5, 2, 1, -285.0, 106801, 0.0, 301, "2025/12/31 12:00:00", "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", "ラビリスタ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021301, 10213, 61, "2030/01/01 14:59:59", 8.204, 2, 1, -285.0, 126501, 0.0, 101, "2026/01/31 12:00:00", "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", "ライラエル");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021302, 10213, 61, "2030/01/01 14:59:59", 7.176, 2, 1, -285.0, 129701, 0.0, 201, "2026/01/31 12:00:00", "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", "ネフィ＝ネラ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021303, 10213, 61, "2030/01/01 14:59:59", 8.602, 5, 1, -285.0, 133101, 0.0, 301, "2026/01/31 12:00:00", "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", "ヴァイオレット");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021304, 10213, 61, "2030/01/01 14:59:59", 10.14, 3, 1, -285.0, 138101, 0.0, 102, "2026/02/06 12:00:00", "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", "ライラエル");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021305, 10213, 61, "2030/01/01 14:59:59", 10.152, 7, 1, -285.0, 138201, 0.0, 202, "2026/02/06 12:00:00", "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", "ネフィ＝ネラ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021306, 10213, 61, "2030/01/01 14:59:59", 9.688, 3, 4, -285.0, 138001, 0.0, 302, "2026/02/06 12:00:00", "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", "ヴァイオレット");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021307, 10213, 61, "2030/01/01 14:59:59", 5.928, 1, 2, -285.0, 138301, 0.0, 401, "2026/02/12 12:00:00", "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", "ペコリーヌ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021401, 10214, 61, "2030/01/01 14:59:59", 9.19, 2, 4, -285.0, 138702, 0.0, 101, "2026/02/28 12:00:00", "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", "ワカナ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021402, 10214, 61, "2030/01/01 14:59:59", 8.724, 3, 1, -285.0, 138802, 0.0, 201, "2026/02/28 12:00:00", "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", "シオリ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021501, 10215, 61, "2030/01/01 14:59:59", 7.758, 1, 4, -285.0, 138902, 0.0, 101, "2026/03/31 12:00:00", "私がへんたいふしんしゃさんって…\nただ生きているだけなのに、ひどい\n…まぁ死んでるんですけど…とか\n言ってる暇もない感じですか？", "グレイス");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021502, 10215, 61, "2030/01/01 14:59:59", 6.375, 4, 6, -285.0, 139002, 0.0, 201, "2026/03/31 12:00:00", "あの、助けてください！\n私がへんたいふしんしゃさんに\nなっちゃったみたいなんです…！\nどういう意味かは私もわかりません", "キョウカ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021503, 10215, 61, "2030/01/01 14:59:59", 6.173, 1, 6, -285.0, 136902, 0.0, 301, "2026/03/31 12:00:00", "ましゃか、グレイス姉しゃまたちが\nへんたいふしんしゃさんだなんて…\n騎士しゃん。あたちたちも協力ちて\n二人の破滅エンドを回避ちましょう", "ルルィ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021601, 10216, 61, "2030/01/01 14:59:59", 4.202, 2, 6, -285.0, 139202, 0.0, 101, "2026/04/30 12:00:00", "違う世界に来ちゃうし、\n驚きの連続だけど…\nわたしも精いっぱい頑張ります！\nアストルムのみんなと一緒に！", "ミホ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021602, 10216, 61, "2030/01/01 14:59:59", 2.842, 1, 6, -285.0, 139302, 0.0, 201, "2026/04/30 12:00:00", "想定外の事象が発生したな…だが\nいかなる苦境も切り抜けてみせる\nいつもの自分とは違う姿になっても\nわたしはわたし、西住流だ", "マホ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021603, 10216, 61, "2030/01/01 14:59:59", 4.598, 1, 4, -285.0, 139402, 0.0, 301, "2026/04/30 12:00:00", "何でこんなことになっているのか\n全然わからないけど、迷ってる暇は\nないわ。黒森峰の次期隊長として、\n前進あるのみ！　これも戦車道よ！", "エリカ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021701, 10217, 61, "2030/01/01 14:59:59", 6.533, 3, 4, -285.0, 125802, 0.0, 101, "2026/05/31 12:00:00", "わたくしたちの悲願は、ロストさせ\nてしまった方々をお助けすること…\nそのためなら、どのような辛苦にも\n耐え抜いてみせます…！", "リリ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021702, 10217, 61, "2030/01/01 14:59:59", 5.0, 3, 3, -285.0, 126102, 0.0, 301, "2026/05/31 12:00:00", "みんなも。せーぎも。\nクリアも。パパ、も。\nぜったい、たすける。\nみててね。お兄。", "プレシア");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021703, 10217, 61, "2030/01/01 14:59:59", 5.214, 4, 3, -285.0, 126002, 0.0, 201, "2026/05/31 12:00:00", "癒しの力を使うこと…\nもう、ためらいません！\nモネちゃんやお兄さん…\nみんなに許してもらうためにも！", "クリア");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021704, 10217, 61, "2030/01/01 14:59:59", 8.781, 3, 1, -285.0, 139501, 0.0, 102, "2026/05/31 12:00:00", "ヴァルキュリア─皆様を助けたい\nという願いを、力にできるのなら…\nわたくしたちは、きっと誰にも\n負けません！　一意専心です…！", "リリ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021705, 10217, 61, "2030/01/01 14:59:59", 6.529, 1, 2, -285.0, 139601, 0.0, 202, "2026/05/31 12:00:00", "このヴァルキュリアって職業、\nまるで天使みたいな格好ですよね\nうーん…『聖女』ちゃんって\n呼ばれるよりは、マシかな？", "クリア");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021706, 10217, 61, "2030/01/01 14:59:59", 3.195, 2, 3, -285.0, 139701, 0.0, 302, "2026/05/31 12:00:00", "ばるきり。もーど。\nはね。まっしろ。\nはっぴーちゃんと。おなじ。\nいいかんじ。", "プレシア");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021801, 10218, 61, "2030/01/01 14:59:59", 12.43, 3, 2, -285.0, 139902, 0.0, 101, "2026/06/30 12:00:00", "ダーリンと一緒に南の島で\nリゾート開発なんて夢みたい♪\nああ…幸せ、最高の夏だわ…\n触れたら爆発さえしなければ～…っ", "ルイズマリー");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1021802, 10218, 61, "2030/01/01 14:59:59", 6.35, 3, 2, -285.0, 140001, 0.0, 201, "2026/06/30 12:00:00", "青い空、白い雲…無人島リゾートで\n大儲けですわ～♪　こらこらそこ、\nイチャついてるんじゃないですのよ\n触れたらドカンですわよ、ドカン！", "クレジッタ");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2000001, 2, 62, "2030/01/01 14:59:59", 3.414, 2, 1, -416.5, 190801, 0.0, 1, "2026/04/10 12:00:00", "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", "カリン");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2000002, 2, 62, "2030/01/01 14:59:59", 3.099, 2, 1, -416.5, 190801, 0.0, 2, "2026/04/10 12:00:00", "ミッションをクリアして、\n報酬をゲットしましょう！", "カリン");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2000003, 2, 63, "2030/01/01 14:59:59", 2.801, 2, 1, -416.5, 190801, 0.0, 3, "2026/04/10 12:00:00", "受け取ることができる\n報酬があるようです\n確認してみてください", "カリン");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2000004, 2, 63, "2030/01/01 14:59:59", 0.0, 2, 2, -416.5, 190801, 0.0, 4, "2026/04/10 12:00:00", "報酬がもらえますよ！\nチェックしてみてください", "カリン");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2000005, 2, 64, "2030/01/01 14:59:59", 2.12, 1, 2, -363.0, 190801, 0.0, 5, "2026/04/10 12:00:00", "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", "カリン");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2000006, 2, 64, "2030/01/01 14:59:59", 1.68, 2, 1, -363.0, 190801, 0.0, 6, "2026/04/10 12:00:00", "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", "カリン");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2000007, 2, 64, "2030/01/01 14:59:59", 2.33, 1, 2, -363.0, 190801, 0.0, 7, "2026/04/10 12:00:00", "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", "カリン");
